from collections import deque

def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    max_edge = 0
    for u, v, cost in edges:
        if cost > max_edge:
            max_edge = cost

    def is_possible(mid):
        adj = [[] for _ in range(n)]
        for u, v, cost in edges:
            if cost >= mid and online[u] and online[v]:
                adj[u].append((v, cost))

        in_degree = [0] * n
        for u in range(n):
            for (v, _) in adj[u]:
                in_degree[v] += 1

        queue = deque()
        for i in range(n):
            if in_degree[i] == 0:
                queue.append(i)

        topo_order = []
        while queue:
            u = queue.popleft()
            topo_order.append(u)
            for (v, _) in adj[u]:
                in_degree[v] -= 1
                if in_degree[v] == 0:
                    queue.append(v)

        INF = float('inf')
        dist = [INF] * n
        dist[0] = 0
        for u in topo_order:
            if dist[u] == INF:
                continue
            for (v, cost) in adj[u]:
                if dist[v] > dist[u] + cost:
                    dist[v] = dist[u] + cost
        return dist[n-1] <= k

    low = 0
    high = max_edge
    answer = -1
    while low <= high:
        mid = (low + high) // 2
        if is_possible(mid):
            answer = mid
            low = mid + 1
        else:
            high = mid - 1
    return answer if answer != -1 else -1
